import java.util.*;

public class IteratorExample {
    public static void main(String[] args) {
        ArrayList<String> list = new ArrayList<>(
            Arrays.asList("Apple", "Banana", "Cherry", "Date", "Elderberry")
        );

        System.out.println("Original: " + list);

        // 1. For-each loop (read-only)
        System.out.println("=== For-Each Loop ===");
        for (String fruit : list) {
            System.out.println("  " + fruit);
        }

        // 2. Iterator
        System.out.println("=== Iterator ===");
        Iterator<String> it = list.iterator();
        while (it.hasNext()) {
            String fruit = it.next();
            System.out.println("  " + fruit);
        }

        // 3. Removing while iterating with Iterator
        System.out.println("=== Removing with Iterator ===");
        it = list.iterator();
        while (it.hasNext()) {
            String fruit = it.next();
            if (fruit.startsWith("A") || fruit.startsWith("D")) {
                it.remove();  // Safe removal!
            }
        }
        System.out.println("After removing A and D: " + list);

        // 4. ListIterator (bidirectional)
        System.out.println("=== ListIterator (forward) ===");
        ListIterator<String> listIt = list.listIterator();
        while (listIt.hasNext()) {
            String fruit = listIt.next();
            System.out.println("  " + fruit);
        }

        System.out.println("=== ListIterator (backward) ===");
        while (listIt.hasPrevious()) {
            String fruit = listIt.previous();
            System.out.println("  " + fruit);
        }

        // 5. ListIterator with modification
        System.out.println("=== ListIterator with Add/Set ===");
        listIt = list.listIterator();
        while (listIt.hasNext()) {
            String fruit = listIt.next();
            if (fruit.equals("Banana")) {
                listIt.set("Blueberry");  // Replace
            }
            if (fruit.equals("Cherry")) {
                listIt.add("Cranberry");  // Insert after
            }
        }
        System.out.println("After modifications: " + list);

        // 6. For-each with map
        System.out.println("=== For-Each with Map ===");
        HashMap<String, Integer> scores = new HashMap<>();
        scores.put("Alice", 95);
        scores.put("Bob", 87);
        scores.put("Charlie", 92);

        for (Map.Entry<String, Integer> entry : scores.entrySet()) {
            System.out.println("  " + entry.getKey() + " = " + entry.getValue());
        }

        // 7. Iterator with primitive array
        System.out.println("=== Array with for-each ===");
        int[] numbers = {1, 2, 3, 4, 5};
        for (int num : numbers) {
            System.out.print(num + " ");
        }
        System.out.println();

        // 8. Performance comparison
        System.out.println("=== Iterator vs For-Each ===");
        // For-each is syntactic sugar for iterator
        // Both have same performance
        // For-each is simpler, but iterator gives more control

        // 9. ConcurrentModificationException demo
        System.out.println("=== Preventing ConcurrentModification ===");
        List<String> list2 = new ArrayList<>(Arrays.asList("A", "B", "C", "D"));

        // BAD: Remove during for-each
        // for (String s : list2) {
        //     if (s.equals("B")) {
        //         list2.remove(s);  // ConcurrentModificationException!
        //     }
        // }

        // GOOD: Use iterator
        Iterator<String> it2 = list2.iterator();
        while (it2.hasNext()) {
            if (it2.next().equals("B")) {
                it2.remove();  // Safe!
            }
        }
        System.out.println("After safe removal: " + list2);

        // Alternative: removeIf
        list2.removeIf(s -> s.equals("C"));
        System.out.println("After removeIf: " + list2);
    }
}

