import java.util.*;

public class IteratorPractice {
    public static void main(String[] args) {
        LinkedList<Integer> numbers = new LinkedList<>();
        for (int i = 1; i <= 10; i++) {
            numbers.add(i);
        }
        System.out.println("Original: " + numbers);

        // Remove even numbers
        Iterator<Integer> it = numbers.iterator();
        while (it.hasNext()) {
            int n = it.next();
            if (n % 2 == 0) {
                it.remove();
            }
        }
        System.out.println("After removing evens: " + numbers);

        // Add 0 at beginning, 11 at end
        ListIterator<Integer> listIt = numbers.listIterator();
        listIt.add(0);  // Add at beginning
        while (listIt.hasNext()) {
            listIt.next();
        }
        listIt.add(11);  // Add at end

        System.out.println("Final: " + numbers);

        // For-each print
        System.out.println("Printing with for-each:");
        for (int n : numbers) {
            System.out.print(n + " ");
        }
        System.out.println();
    }
}
